const months = {1:'ינואר',2:'פברואר',3:'מרץ',4:'אפריל',5:'מאי',6:'יוני',7:'יולי',8:'אוגוסט',9:'ספטמבר',10:'אוקטובר',11:'נובמבר',12:'דצמבר'};
const now = new Date();
const israelOffset = 3 * 60;
const localTime = new Date(now.getTime() + israelOffset * 60000);
const day = localTime.getUTCDate();
const month = localTime.getUTCMonth() + 1;
const year = localTime.getUTCFullYear();
const sheetName = day + ' ' + months[month];
const isoDate = year + '-' + String(month).padStart(2,'0') + '-' + String(day).padStart(2,'0');
return [{ json: { sheetName, isoDate } }];

const rows = ($input.first().json.values || []);
const isoDate = $('Build Today Sheet').first().json.isoDate;
if (rows.length === 0) return [];

// Find the actual header row (contains 'משימה' or 'שם טכנאי')
let headerRowIdx = -1;
let taskColIndices = [];
for (let r = 0; r < Math.min(rows.length, 5); r++) {
  const row = rows[r] || [];
  const hasTask = row.some(h => String(h).trim() === 'משימה');
  const hasTech = row.some(h => String(h).includes('שם טכנאי'));
  if (hasTask || hasTech) {
    headerRowIdx = r;
    for (let c = 0; c < row.length; c++) {
      if (String(row[c]).trim() === 'משימה') taskColIndices.push(c);
    }
    break;
  }
}
if (taskColIndices.length === 0) taskColIndices = [3, 4, 5, 6];
const startRow = headerRowIdx >= 0 ? headerRowIdx + 1 : 2;

// Values that mean no actual work task
const skipWords = ['חופש', 'מילואים', 'חה"ש', 'מחלה', 'גיוס'];

let currentDept = '';
const tasks = [];

for (let r = startRow; r < rows.length; r++) {
  const row = rows[r];
  if (!row || row.length < 2) continue;

  const col0 = String(row[0] || '').trim();  // dept section label or empty
  const col1 = String(row[1] || '').trim();  // tech first name
  const col2 = String(row[2] || '').trim();  // second tech or last name

  // Track department from section headers in col0
  if (col0 && !col0.includes('|') && !col0.includes(':') && !col0.includes('/')) {
    currentDept = col0;
  }

  // Skip rows with no technician name
  if (!col1) continue;

  // Build tech name: combine col1 + col2 if both present
  const techName = (col2 && col2 !== col1) ? col1 + ' ' + col2 : col1;

  // Extract tasks from task columns
  for (const c of taskColIndices) {
    const cellVal = String(row[c] || '').trim();
    if (!cellVal) continue;
    if (skipWords.some(w => cellVal.includes(w))) continue;
    tasks.push({ json: { techName, freeText: cellVal, isoDate, sheetDept: currentDept || null } });
  }
}
return tasks;

const tasks = $input.all().map((item, idx) => ({
  task_index: idx,
  techName: item.json.techName,
  freeText: item.json.freeText,
  isoDate: item.json.isoDate,
  sheetDept: item.json.sheetDept || null
}));
const isoDate = tasks[0]?.isoDate || '';
return [{ json: { tasks, isoDate } }];

const tasks = $('Aggregate Tasks').first().json.tasks || [];
const isoDate = $('Aggregate Tasks').first().json.isoDate || '';

// Load Customers/Sites/Technicians may return N items (one per entity) or 1 item with wrapper
// Use .all() and handle both cases
function extractList(nodeName) {
  const items = $(nodeName).all();
  if (items.length === 0) return [];
  const first = items[0].json;
  // If first item looks like an entity (has 'id'), assume items are individual entities
  if (first.id) return items.map(i => i.json);
  // Otherwise unwrap from entities/data wrapper
  return first.entities || first.data || [];
}

const custList = extractList('Load Customers').map(c => ({ id: c.id, name: c.name }));
const siteList = extractList('Load Sites').map(s => ({ id: s.id, name: s.name, customer_id: s.customer_id }));
const techList = extractList('Load Technicians').map(t => ({ id: t.id, full_name: t.full_name, department: t.department }));

const prompt = `You are a service call identification assistant for an Israeli fire protection company. Tasks are in Hebrew.

DEPARTMENT MAPPING (sheetDept field is the Hebrew section header from the schedule):
- שירות → service
- גילוי → fire_detection
- מתזים → sprinklers
- משאבות → pumps

CUSTOMERS (${custList.length} total):
${JSON.stringify(custList)}

SITES (${siteList.length} total):
${JSON.stringify(siteList)}

TECHNICIANS (${techList.length} total):
${JSON.stringify(techList)}

TASKS FROM TODAY'S SCHEDULE:
${JSON.stringify(tasks)}

For each task:
- Match techName to the closest technician full_name. Accept partial first-name match (e.g. 'טל' matches 'טל רוטהולץ').
- Match freeText to customer name (ok=clear match, maybe=partial/city hint, none=no recognizable match).
- Match freeText to site name (ok=clear match, maybe=partial, none=no match).
- Use sheetDept as the primary department hint (map using DEPARTMENT MAPPING). If sheetDept is null, infer from freeText.

Return ONLY a valid JSON array, no code blocks, no markdown:
[{"task_index":0,"technician_id":"...or null","customer_id":"...or null","customer_match":"ok|maybe|none","site_id":"...or null","site_match":"ok|maybe|none","department":"service|pumps|sprinklers|fire_detection"}]`;

return [{ json: { prompt, tasks, isoDate, techList } }];

const claudeResponse = $input.first().json;
const rawText = (claudeResponse.content || []).find(c => c.type === 'text')?.text || '[]';

let matches = [];
try {
  const jsonMatch = rawText.match(/\[\s*\{[\s\S]*?\}\s*\]/);
  if (jsonMatch) matches = JSON.parse(jsonMatch[0]);
  else matches = JSON.parse(rawText.trim());
} catch(e) {
  return [];
}

const tasks = $('Build Claude Prompt').first().json.tasks || [];
const techList = $('Build Claude Prompt').first().json.techList || [];
const isoDate = $('Build Claude Prompt').first().json.isoDate || '';

return matches.map(m => {
  const task = tasks[m.task_index] || {};
  const tech = techList.find(t => t.id === m.technician_id) || {};
  return {
    json: {
      isoDate,
      techName: task.techName || '',
      freeText: task.freeText || '',
      technician_id: m.technician_id || '',
      technician_name: tech.full_name || task.techName || '',
      customer_id: m.customer_id || null,
      site: m.site_id || null,
      customer_match: m.customer_match || 'none',
      site_match: m.site_match || 'none',
      department: m.department || null
    }
  };
});

// existingDrafts comes from Safe Load Drafts (always 1 item)
const existingDrafts = ($input.first()?.json?.existingDrafts) || [];
// Use technician_name + free_text as stable idempotency key (technician_id may be null on first pass)
const existingKeys = new Set(existingDrafts.map(e => 
  (e.technician_name || '').trim() + '|' + (e.free_text || '').trim()
));

// All matched tasks from Parse Matches
const matchedItems = $('Parse Matches').all();

const newItems = matchedItems.filter(item => {
  const key = (item.json.technician_name || item.json.techName || '').trim() + '|' + (item.json.freeText || '').trim();
  return !existingKeys.has(key);
});

return newItems.map(item => ({ json: item.json }));

// Normalize Load Existing Drafts response — always output exactly 1 item
const items = $input.all();
let drafts = [];
if (items.length > 0) {
  const body = items[0].json;
  if (Array.isArray(body)) {
    drafts = body;
  } else {
    drafts = body.entities || body.data || [];
  }
}
return [{ json: { existingDrafts: drafts } }];
